preambleRaw:
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../e2e/helpers.sh"

require_commands multipass curl jq

# ---------------------------------------------------------------------------
# VM exec helpers
# ---------------------------------------------------------------------------

host_exec() { multipass exec lamaste-host -- sudo bash -c "$1"; }

host_api_get() {
  host_exec "curl -skf --max-time 30 --cert /etc/lamalibre/lamaste/pki/client.crt --key /etc/lamalibre/lamaste/pki/client.key --cacert /etc/lamalibre/lamaste/pki/ca.crt -H 'Accept: application/json' 'https://127.0.0.1:9292/api/$1'"
}

host_api_post() {
  # timed_exec wraps multipass to bound pipe-leak hangs (memory feedback_multipass_exec_patterns.md rule 3).
  # Observed on POST /api/gatekeeper/groups/NAME/members: the server responds in <1s but multipass keeps spinning.
  timed_exec 35 multipass exec lamaste-host -- sudo bash -c "curl -skf --max-time 30 --cert /etc/lamalibre/lamaste/pki/client.crt --key /etc/lamalibre/lamaste/pki/client.key --cacert /etc/lamalibre/lamaste/pki/ca.crt -X POST -H 'Content-Type: application/json' -H 'Accept: application/json' -d '$2' 'https://127.0.0.1:9292/api/$1'"
}

host_api_post_status() {
  timed_exec 35 multipass exec lamaste-host -- sudo bash -c "curl -sk --max-time 30 -o /dev/null -w '%{http_code}' --cert /etc/lamalibre/lamaste/pki/client.crt --key /etc/lamalibre/lamaste/pki/client.key --cacert /etc/lamalibre/lamaste/pki/ca.crt -X POST -H 'Content-Type: application/json' -d '$2' 'https://127.0.0.1:9292/api/$1'"
}

host_api_delete() {
  timed_exec 35 multipass exec lamaste-host -- sudo bash -c "curl -skf --max-time 30 --cert /etc/lamalibre/lamaste/pki/client.crt --key /etc/lamalibre/lamaste/pki/client.key --cacert /etc/lamalibre/lamaste/pki/ca.crt -X DELETE 'https://127.0.0.1:9292/api/$1'"
}

host_api_delete_status() {
  timed_exec 35 multipass exec lamaste-host -- sudo bash -c "curl -sk --max-time 30 -o /dev/null -w '%{http_code}' --cert /etc/lamalibre/lamaste/pki/client.crt --key /etc/lamalibre/lamaste/pki/client.key --cacert /etc/lamalibre/lamaste/pki/ca.crt -X DELETE 'https://127.0.0.1:9292/api/$1'"
}

host_api_get_status() {
  host_exec "curl -sk --max-time 30 -o /dev/null -w '%{http_code}' --cert /etc/lamalibre/lamaste/pki/client.crt --key /etc/lamalibre/lamaste/pki/client.key --cacert /etc/lamalibre/lamaste/pki/ca.crt -H 'Accept: application/json' 'https://127.0.0.1:9292/api/$1'"
}

host_api_patch() {
  timed_exec 35 multipass exec lamaste-host -- sudo bash -c "curl -skf --max-time 30 --cert /etc/lamalibre/lamaste/pki/client.crt --key /etc/lamalibre/lamaste/pki/client.key --cacert /etc/lamalibre/lamaste/pki/ca.crt -X PATCH -H 'Content-Type: application/json' -H 'Accept: application/json' -d '$2' 'https://127.0.0.1:9292/api/$1'"
}

begin_test "21 — Gatekeeper Authorization (Three-VM)"
